// // This module implements a 16-bit down counter that decrements its value on each positive edge of the clock. The counter resets to 0 when the reset signal is asserted (active high). It also has a 16-bit output that reflects its current value. Additionally, it implements a load feature that allows setting the counter to a specific value when the load signal is high.
module counter_16bit (
    input clk,
    input reset,
    input load,
    input [15:0] load_value,
    output reg [15:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 16'b0;
        end else if (load) begin
            count <= load_value;
        end else begin
            count <= count + 1;
        end
    end
endmodule
